import{_ as t,a as o}from"./chunks/pcb-generator-panel-dark.BCzVKhJW.js";import{_ as a}from"./chunks/via-layout-example.yiytcZ4t.js";import{_ as i,o as r,c as n,ag as s}from"./chunks/framework.wGDfT7ie.js";const l="/docs/pcb-generator-footprint-preview-light.png",c="/docs/pcb-generator-footprint-preview-dark.png",k=JSON.parse('{"title":"PCB Generator","description":"","frontmatter":{},"headers":[],"relativePath":"pcb-generator.md","filePath":"pcb-generator.md"}'),d={name:"pcb-generator.md"};function h(p,e,g,u,m,f){return r(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="pcb-generator" tabindex="-1">PCB Generator <a class="header-anchor" href="#pcb-generator" aria-label="Permalink to &quot;PCB Generator&quot;">​</a></h1><p>The PCB Generator creates <a href="https://kicad.org" target="_blank" rel="noreferrer">KiCad</a> project files from your keyboard layout. It generates a key matrix schematic, places switch and diode footprints according to key positions, and can optionally route connections between components.</p><img src="'+t+'" class="docs-screenshot light-only" alt="PCB generator panel"><img src="'+o+'" class="docs-screenshot dark-only" alt="PCB generator panel"><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview {#overview}&quot;">​</a></h2><p>Open the <strong>PCB Generator</strong> panel. The panel displays a footprint preview and generation controls. After project generation the footprint preview is replaced with preview of the resulting schematic and PCB file.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites {#prerequisites}&quot;">​</a></h2><p>Before generating a PCB, your layout must have:</p><ul><li><strong>Matrix coordinates</strong> — Each key must have row/column assignments in VIA label format (e.g., <code>0,0</code> for row 0, column 0). Use <a href="./layout-editor.html#add-switch-matrix-coordinates">Add Switch Matrix Coordinates</a> if not already set.</li><li><strong>Maximum 150 keys</strong> — Layouts with more than 150 keys are not supported.</li></ul><p>Matrix coordinates determine how switches are wired in the keyboard matrix.</p><p><img src="'+a+'" alt="VIA layout example showing matrix coordinates" class="docs-screenshot"></p><h2 id="matrix-coordinates" tabindex="-1">Matrix Coordinates <a class="header-anchor" href="#matrix-coordinates" aria-label="Permalink to &quot;Matrix Coordinates {#matrix-coordinates}&quot;">​</a></h2><p>Matrix coordinates in kle-ng use VIA label format. Each key&#39;s top-left label contains the row and column assignment as <code>row,col</code> (e.g., <code>0,0</code>, <code>0,1</code>, <code>1,0</code>).</p><p>The easiest way to assign matrix coordinates is to use <a href="./layout-editor.html#add-switch-matrix-coordinates">Add Switch Matrix Coordinates</a>, which can annotate your layout automatically or let you draw rows and columns manually.</p><h2 id="generating" tabindex="-1">Generating a PCB <a class="header-anchor" href="#generating" aria-label="Permalink to &quot;Generating a PCB {#generating}&quot;">​</a></h2><ol><li>Verify your layout has matrix coordinates assigned</li><li>Open the <strong>PCB Generator</strong> panel</li><li>Configure switch, diode, and routing options as needed</li><li>Use the preview window to check key-diode placement</li></ol><img src="'+l+'" class="docs-screenshot light-only" alt="PCB footprints preview" style="max-width:50%;"><img src="'+c+'" class="docs-screenshot dark-only" alt="PCB footprints preview" style="max-width:50%;"><ol start="5"><li>Click <strong>Generate PCB</strong></li><li>Wait for the server to process your layout</li><li>Once complete, preview renders will be displayed</li><li>Click <strong>Download ZIP</strong> to save the archive, or <strong>New Task</strong> to start over</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The preview does not support displaying traces for <strong>Routing</strong> option enabled.</p></div><div class="warning custom-block"><p class="custom-block-title">Automatic Routing Limitations</p><p>The automatic router attempts to connect switches to diodes using a basic algorithm that finds the shortest path with 45° angles. <strong>Important limitations:</strong></p><ul><li><strong>Incomplete routing</strong> — The router may leave connections unrouted if it encounters layout obstacles. It does not try alternative paths; it simply skips difficult connections.</li><li><strong>DRC required</strong> — Always run KiCad&#39;s Design Rule Check after generation to identify unrouted nets.</li><li><strong>Manual finishing needed</strong> — The generated PCB is a starting point and requires manual review and completion in KiCad.</li></ul></div><h2 id="after-downloading-the-pcb" tabindex="-1">After Downloading the PCB <a class="header-anchor" href="#after-downloading-the-pcb" aria-label="Permalink to &quot;After Downloading the PCB&quot;">​</a></h2><p>The downloaded ZIP archive contains two files:</p><ul><li><strong><code>.kicad_sch</code></strong> — Schematic with the switch matrix</li><li><strong><code>.kicad_pcb</code></strong> — Board file with switch footprints placed according to key positions and matrix coordinates, diode footprints for each switch, routed connections (if routing was enabled)</li></ul><p>Extract the ZIP and open the <code>.kicad_pcb</code> file in KiCad 9+ to continue PCB design.</p><h3 id="next-steps-in-kicad" tabindex="-1">Next Steps in KiCad <a class="header-anchor" href="#next-steps-in-kicad" aria-label="Permalink to &quot;Next Steps in KiCad&quot;">​</a></h3><p>Typical next steps after downloading:</p><ol><li><strong>Add a microcontroller</strong> — Place your MCU footprint (e.g., Pro Micro, RP2040) and connect row/column lines.</li><li><strong>Add a USB connector</strong> — Route the data lines from the MCU to the connector.</li><li><strong>Add mounting holes</strong> — Use the footprint library to place M2 or M3 standoff holes.</li><li><strong>Add the edge cut</strong> — Generator does not include PCB outline; create it to match your intended case.</li><li><strong>Run DRC</strong> — Use KiCad&#39;s Design Rule Check to catch errors before sending to fabrication.</li></ol><h2 id="tips-and-best-practices" tabindex="-1">Tips and Best Practices <a class="header-anchor" href="#tips-and-best-practices" aria-label="Permalink to &quot;Tips and Best Practices&quot;">​</a></h2><h3 id="download-and-service-limits" tabindex="-1">Download and Service Limits <a class="header-anchor" href="#download-and-service-limits" aria-label="Permalink to &quot;Download and Service Limits&quot;">​</a></h3><ul><li><strong>Download expiration</strong> — Generated PCB files expire after <strong>1 hour</strong>.</li><li><strong>Rate limiting</strong> — There is a 5-second cooldown between generation requests.</li><li><strong>Worker status</strong> — The PCB generator runs on a remote worker. If the service is temporarily unavailable, try again later.</li></ul><h3 id="kicad-compatibility" tabindex="-1">KiCad Compatibility <a class="header-anchor" href="#kicad-compatibility" aria-label="Permalink to &quot;KiCad Compatibility&quot;">​</a></h3><p>Generated files are compatible with <strong>KiCad 9+</strong>. Open the file in KiCad to add mounting holes, USB connector, microcontroller, and other components.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="missing-via-json-export" tabindex="-1">Missing VIA JSON Export <a class="header-anchor" href="#missing-via-json-export" aria-label="Permalink to &quot;Missing VIA JSON Export&quot;">​</a></h3><p><strong>&quot;Download VIA JSON&quot; option is missing</strong> — This is a separate export from <strong>Import &amp; Export</strong>. For PCB generation, you only need matrix coordinates on the keys, not a full VIA metadata block.</p><h3 id="missing-keys-in-output" tabindex="-1">Missing Keys in Output <a class="header-anchor" href="#missing-keys-in-output" aria-label="Permalink to &quot;Missing Keys in Output&quot;">​</a></h3><p><strong>Keys are missing from the generated PCB</strong> — Only keys with valid matrix coordinates (<code>row,col</code> in the top-left label) are included. Use <a href="./layout-editor.html#add-switch-matrix-coordinates">Add Switch Matrix Coordinates</a> to assign coordinates to all keys, then verify none are missing.</p><h3 id="service-unavailability" tabindex="-1">Service Unavailability <a class="header-anchor" href="#service-unavailability" aria-label="Permalink to &quot;Service Unavailability&quot;">​</a></h3><p><strong>The PCB worker is unavailable</strong> — The generator uses a remote server. If requests fail, try again after a few minutes. Your layout data is not lost — regenerate from the same layout.</p><div class="info custom-block"><p class="custom-block-title">Privacy note</p><p>This feature sends your layout data to a backend server for processing. Generated files are stored for 1 hour and then automatically deleted. No data is used for any other purposes.</p></div>',41)])])}const v=i(d,[["render",h]]);export{k as __pageData,v as default};
